import { useState } from "react";
import api from "../../api/axios";
import Input from "../../components/Input";
import { useNavigate } from "react-router-dom";

export default function Login() {
  const [form, setForm] = useState({ email: "", password: "" });
  const navigate = useNavigate();

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      const res = await api.post("/users/login", form);
      // store token if your backend returns one
      localStorage.setItem("token", res.data.token);
      alert("Login successful!");
      navigate("/leads"); // redirect to dashboard
    } catch (err) {
      alert(err.response?.data?.message || "Login failed");
    }
  };

  return (
    <div style={{ maxWidth: "400px", margin: "50px auto" }}>
      <h2>Login</h2>
      <form onSubmit={handleSubmit}>
        <Input name="email" label="Email" value={form.email} onChange={handleChange} />
        <Input name="password" type="password" label="Password" value={form.password} onChange={handleChange} />
        <button type="submit" style={{ padding: "10px 20px", marginTop: "10px" }}>Login</button>
      </form>
    </div>
  );
}
